#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(Int c(a);c>=(b);--c)
using namespace std;
typedef long long ll;ll L,R,K;const int M=250;
int n,a[60];ll f[60][500][2],g[60][500][2];
inline ll work(int x,int C,bool oe)
{
	memset(f,0,sizeof(f));
	memset(g,0,sizeof(g));
	f[0][M][0]=f[0][M][1]=0;
	g[0][M][0]=g[0][M][1]=1;
	int l=0,r=0;
	rep(0,n-1,B)//数位
	{
		r=min(r,2*C);
		rep(l,r,i)//枚举2*S-T; 
		{
			ll *F=f[B][i+M],*G=g[B][i+M];
			rep(0,K-1,j)//枚举B+1位填啥
			{
				if(B+1==x)j=C;
//				if(i+j>2*C)break;
				int ni=(B+1<x?i-j:i+j)+M;
				g[B+1][ni][0]+=G[0];
				f[B+1][ni][0]+=G[0]*abs(B+1-x)*j+F[0];
				if(j<=a[B+1])
				{
					bool z=(j==a[B+1]);
					g[B+1][ni][1]+=G[z];
					f[B+1][ni][1]+=G[z]*abs(B+1-x)*j+F[z];
				}
//				printf("(%d,%d) --(%d)-> (%d,%d) [%lld],[%lld]\n",B,i,j,B+1,ni-M,F[0],f[B+1][ni][0]);
				if(B+1==x)break;
			}
		}
		if(B+1<x) l-=K-1;
		else if(B+1==x)l+=C,r+=C;
		else r+=K-1;
	}
	ll ans=0;
	rep(1,2*C,S)if((S&1)==oe)ans+=f[n][S+M][1];//,printf("add (%d,%d) :: %lld\n",n,S,f[n][S+M][1]);
//	printf("work(%d,%d,%d) :: %lld\n",x,C,oe,ans);
//	puts("<<<<<<<<<<<");
	return ans;
}
inline ll S(ll x)
{
	n=0;while(x)a[++n]=x%K,x/=K;ll ans=0;
//	printf("a :: ");rep(1,n,i)printf("%d ",a[i]);puts("");
	rep(1,n,i)rep(1,K-1,j)ans+=work(i,j,0)+work(i,j,1);
	return ans;
}
int main()
{
	cin>>L>>R>>K;
	cout<<S(R)-S(L-1)<<'\n';
}
